    86→// New creates a new etcdv3 client from a given configuration.
    87→func New(cfg Config) (*Client, error) {
    88→	if len(cfg.Endpoints) == 0 {
    89→		return nil, ErrNoAvailableEndpoints
    90→	}
    91→
    92→	return newClient(&cfg)
    93→}
    94→
    95→// NewCtxClient creates a client with a context but no underlying grpc
    96→// connection. This is useful for embedded cases that override the
    97→// service interface implementations and do not need connection management.
    98→func NewCtxClient(ctx context.Context, opts ...Option) *Client {
    99→	cctx, cancel := context.WithCancel(ctx)
   100→	c := &Client{ctx: cctx, cancel: cancel, epMu: new(sync.RWMutex)}
   101→	for _, opt := range opts {
   102→		opt(c)
   103→	}
   104→	if c.lg.Load() == nil {
   105→		c.lg.Store(zap.NewNop())
   106→	}
   107→	return c
   108→}
   109→
   110→// Option is a function type that can be passed as argument to NewCtxClient to configure client
   111→type Option func(*Client)
   112→
   113→// NewFromURL creates a new etcdv3 client from a URL.
   114→func NewFromURL(url string) (*Client, error) {
   115→	return New(Config{Endpoints: []string{url}})
   116→}
   117→
   118→// NewFromURLs creates a new etcdv3 client from URLs.
   119→func NewFromURLs(urls []string) (*Client, error) {
   120→	return New(Config{Endpoints: urls})
   121→}
   122→
   123→// WithZapLogger is a NewCtxClient option that overrides the logger
   124→func WithZapLogger(lg *zap.Logger) Option {
   125→	return func(c *Client) {
   126→		c.lg.Store(lg)
   127→	}
   128→}
   129→
   130→// WithLogger overrides the logger.
   131→//
   132→// Deprecated: Please use WithZapLogger or Logger field in clientv3.Config
   133→//
   134→// Does not changes grpcLogger, that can be explicitly configured
   135→// using grpc_zap.ReplaceGrpcLoggerV2(..) method.
   136→func (c *Client) WithLogger(lg *zap.Logger) *Client {
   137→	c.lg.Store(lg)
   138→	return c
   139→}
   140→
   141→// GetLogger gets the logger.
   142→// NOTE: This method is for internal use of etcd-client library and should not be used as general-purpose logger.
   143→func (c *Client) GetLogger() *zap.Logger {
   144→	return c.lg.Load()
   145→}
