   147→// Close shuts down the client's etcd connections.
   148→func (c *Client) Close() error {
   149→	c.cancel()
   150→	if c.Watcher != nil {
   151→		c.Watcher.Close()
   152→	}
   153→	if c.Lease != nil {
   154→		c.Lease.Close()
   155→	}
   156→	if c.conn != nil {
   157→		return ContextError(c.ctx, c.conn.Close())
   158→	}
   159→	return c.ctx.Err()
   160→}
