   167→// Endpoints lists the registered endpoints for the client.
   168→func (c *Client) Endpoints() []string {
   169→	// copy the slice; protect original endpoints from being changed
   170→	c.epMu.RLock()
   171→	defer c.epMu.RUnlock()
   172→	eps := make([]string, len(c.endpoints))
   173→	copy(eps, c.endpoints)
   174→	return eps
   175→}
   176→
   177→// SetEndpoints updates client's endpoints.
   178→func (c *Client) SetEndpoints(eps ...string) {
   179→	c.epMu.Lock()
   180→	defer c.epMu.Unlock()
   181→	c.endpoints = eps
   182→
   183→	c.resolver.SetEndpoints(eps)
   184→}
   185→
   186→// Sync synchronizes client's endpoints with the known endpoints from the etcd membership.
   187→func (c *Client) Sync(ctx context.Context) error {
   188→	mresp, err := c.MemberList(ctx)
   189→	if err != nil {
   190→		return err
   191→	}
   192→	var eps []string
   193→	for _, m := range mresp.Members {
   194→		if len(m.Name) != 0 && !m.IsLearner {
   195→			eps = append(eps, m.ClientURLs...)
   196→		}
   197→	}
   198→	// The linearizable `MemberList` returned successfully, so the
   199→	// endpoints shouldn't be empty.
   200→	verify.Verify("empty endpoints returned from etcd cluster", func() (bool, map[string]any) {
   201→		return len(eps) > 0, nil
   202→	})
   203→	c.SetEndpoints(eps...)
   204→	c.GetLogger().Debug("set etcd endpoints by autoSync", zap.Strings("endpoints", eps))
   205→	return nil
   206→}
   207→
   208→func (c *Client) autoSync() {
   209→	if c.cfg.AutoSyncInterval == time.Duration(0) {
   210→		return
   211→	}
   212→
   213→	for {
   214→		select {
   215→		case <-c.ctx.Done():
   216→			return
   217→		case <-time.After(c.cfg.AutoSyncInterval):
   218→			ctx, cancel := context.WithTimeout(c.ctx, 5*time.Second)
   219→			err := c.Sync(ctx)
   220→			cancel()
   221→			if err != nil && !errors.Is(err, c.ctx.Err()) {
   222→				c.GetLogger().Info("Auto sync endpoints failed.", zap.Error(err))
   223→			}
   224→		}
   225→	}
   226→}
