   230→	var opts []grpc.DialOption
   231→
   232→	if c.cfg.DialKeepAliveTime > 0 {
   233→		params := keepalive.ClientParameters{
   234→			Time:                c.cfg.DialKeepAliveTime,
   235→			Timeout:             c.cfg.DialKeepAliveTimeout,
   236→			PermitWithoutStream: c.cfg.PermitWithoutStream,
   237→		}
   238→		opts = append(opts, grpc.WithKeepaliveParams(params))
   239→	}
   240→	opts = append(opts, dopts...)
   241→
   242→	if creds != nil {
   243→		opts = append(opts, grpc.WithTransportCredentials(creds))
   244→	} else {
   245→		opts = append(opts, grpc.WithTransportCredentials(insecure.NewCredentials()))
   246→	}
   247→
   248→	unaryMaxRetries := defaultUnaryMaxRetries
   249→	if c.cfg.MaxUnaryRetries > 0 {
   250→		unaryMaxRetries = c.cfg.MaxUnaryRetries
   251→	}
   252→
   253→	backoffWaitBetween := defaultBackoffWaitBetween
   254→	if c.cfg.BackoffWaitBetween > 0 {
   255→		backoffWaitBetween = c.cfg.BackoffWaitBetween
   256→	}
   257→
   258→	backoffJitterFraction := defaultBackoffJitterFraction
   259→	if c.cfg.BackoffJitterFraction > 0 {
   260→		backoffJitterFraction = c.cfg.BackoffJitterFraction
   261→	}
   262→
   263→	// Interceptor retry and backoff.
   264→	// TODO: Replace all of clientv3/retry.go with RetryPolicy:
   265→	// https://github.com/grpc/grpc-proto/blob/cdd9ed5c3d3f87aef62f373b93361cf7bddc620d/grpc/service_config/service_config.proto#L130
   266→	rrBackoff := withBackoff(c.roundRobinQuorumBackoff(backoffWaitBetween, backoffJitterFraction))
   267→	opts = append(opts,
   268→		// Disable stream retry by default since go-grpc-middleware/retry does not support client streams.
   269→		// Streams that are safe to retry are enabled individually.
   270→		grpc.WithStreamInterceptor(c.streamClientInterceptor(withMax(0), rrBackoff)),
   271→		grpc.WithUnaryInterceptor(c.unaryClientInterceptor(withMax(unaryMaxRetries), rrBackoff)),
   272→	)
   273→
   274→	return opts
   275→}
