   277→// Dial connects to a single endpoint using the client's config.
   278→func (c *Client) Dial(ep string) (*grpc.ClientConn, error) {
   279→	creds := c.credentialsForEndpoint(ep)
   280→
   281→	// Using ad-hoc created resolver, to guarantee only explicitly given
   282→	// endpoint is used.
   283→	return c.dial(creds, grpc.WithResolvers(resolver.New(ep)))
