   310→// dialWithBalancer dials the client's current load balanced resolver group.  The scheme of the host
   311→// of the provided endpoint determines the scheme used for all endpoints of the client connection.
   312→func (c *Client) dialWithBalancer(dopts ...grpc.DialOption) (*grpc.ClientConn, error) {
   313→	creds := c.credentialsForEndpoint(c.Endpoints()[0])
   314→	opts := append(dopts, grpc.WithResolvers(c.resolver))
   315→	return c.dial(creds, opts...)
   316→}
