   318→// dial configures and dials any grpc balancer target.
   319→func (c *Client) dial(creds grpccredentials.TransportCredentials, dopts ...grpc.DialOption) (*grpc.ClientConn, error) {
   320→	opts := c.dialSetupOpts(creds, dopts...)
   321→
   322→	if c.authTokenBundle != nil {
   323→		opts = append(opts, grpc.WithPerRPCCredentials(c.authTokenBundle.PerRPCCredentials()))
   324→	}
   325→
   326→	opts = append(opts, c.cfg.DialOptions...)
   327→
   328→	target := fmt.Sprintf("%s://%p/%s", resolver.Schema, c, authority(c.endpoints[0]))
   329→	conn, err := grpc.NewClient(target, opts...)
   330→	if err != nil {
   331→		return nil, err
   332→	}
   333→	if dialTimeout := c.cfg.DialTimeout; dialTimeout > 0 {
   334→		dctx, cancel := context.WithTimeout(c.ctx, dialTimeout)
   335→		defer cancel()
   336→
   337→		if err := waitForConnection(dctx, conn); err != nil {
   338→			conn.Close()
   339→			return nil, err
   340→		}
   341→	}
   342→	return conn, nil
   343→}
   344→
   345→func waitForConnection(ctx context.Context, conn *grpc.ClientConn) error {
   346→	cli := healthpb.NewHealthClient(conn)
   347→
   348→	// Use WaitForReady to wait until the connection is ready. The health check
   349→	// may return Unimplemented if the server does not expose the health endpoint,
   350→	// or FailedPrecondition if the leader has not yet applied the configuration
   351→	// change that enables it. In both cases, we can still treat the connection as
   352→	// healthy enough to proceed.
   353→	//
   354→	// Use withMax to disable retrying on Unimplemented, so that we can
   355→	// return the original error immediately.
   356→	_, err := cli.Check(ctx, &healthpb.HealthCheckRequest{}, grpc.WaitForReady(true), withMax(0))
   357→	if err == nil {
   358→		return nil
   359→	}
   360→	if cerr := ctx.Err(); cerr != nil {
   361→		if serr, ok := status.FromError(err); ok && serr.Message() != "" {
   362→			return fmt.Errorf("etcdclient: failed to connect to the etcd server: %s: %w", serr.Message(), cerr)
   363→		}
   364→		return fmt.Errorf("etcdclient: failed to connect to the etcd server: %w", cerr)
   365→	}
   366→
   367→	serr, ok := status.FromError(err)
   368→	if ok {
   369→		switch serr.Code() {
   370→		case codes.Unimplemented, codes.FailedPrecondition:
   371→			return nil
   372→		}
   373→	}
   374→	return fmt.Errorf("etcdclient: failed to dial by invoking health endpoint: %w", err)
   375→}
