   391→func (c *Client) credentialsForEndpoint(ep string) grpccredentials.TransportCredentials {
   392→	r := endpoint.RequiresCredentials(ep)
   393→	switch r {
   394→	case endpoint.CredsDrop:
   395→		return nil
   396→	case endpoint.CredsOptional:
   397→		return c.creds
   398→	case endpoint.CredsRequire:
   399→		if c.creds != nil {
   400→			return c.creds
   401→		}
   402→		return credentials.NewTransportCredential(nil)
   403→	default:
   404→		panic(fmt.Errorf("unsupported CredsRequirement: %v", r))
   405→	}
   406→}
