   408→func newClient(cfg *Config) (*Client, error) {
   409→	if cfg == nil {
   410→		cfg = &Config{}
   411→	}
   412→	var creds grpccredentials.TransportCredentials
   413→	if cfg.TLS != nil {
   414→		creds = credentials.NewTransportCredential(cfg.TLS)
   415→	}
   416→
   417→	if cfg.Token != "" && (cfg.Username != "" || cfg.Password != "") {
   418→		return nil, ErrMutuallyExclusiveCfg
   419→	}
   420→
   421→	// use a temporary skeleton client to bootstrap first connection
   422→	baseCtx := context.TODO()
   423→	if cfg.Context != nil {
   424→		baseCtx = cfg.Context
   425→	}
   426→
   427→	ctx, cancel := context.WithCancel(baseCtx)
   428→	client := &Client{
   429→		conn:     nil,
   430→		cfg:      *cfg,
   431→		creds:    creds,
   432→		ctx:      ctx,
   433→		cancel:   cancel,
   434→		epMu:     new(sync.RWMutex),
   435→		callOpts: defaultCallOpts,
   436→	}
   437→
   438→	var err error
   439→	var lg *zap.Logger
   440→	if cfg.Logger != nil {
   441→		lg = cfg.Logger
   442→	} else if cfg.LogConfig != nil {
   443→		lg, err = cfg.LogConfig.Build()
   444→	} else {
   445→		lg, err = logutil.CreateDefaultZapLogger(ClientLogLevel())
   446→		if lg != nil {
   447→			lg = lg.Named("etcd-client")
   448→		}
   449→	}
   450→	if err != nil {
   451→		return nil, err
   452→	}
   453→	client.lg.Store(lg)
   454→
   455→	if cfg.Username != "" && cfg.Password != "" {
   456→		client.Username = cfg.Username
   457→		client.Password = cfg.Password
   458→		client.authTokenBundle = credentials.NewPerRPCCredentialBundle()
   459→	}
   460→
   461→	if cfg.Token != "" {
   462→		client.Token = cfg.Token
   463→		client.authTokenBundle = credentials.NewPerRPCCredentialBundle()
   464→	}
   465→
   466→	if cfg.MaxCallSendMsgSize > 0 || cfg.MaxCallRecvMsgSize > 0 {
   467→		if cfg.MaxCallRecvMsgSize > 0 && cfg.MaxCallSendMsgSize > cfg.MaxCallRecvMsgSize {
   468→			return nil, fmt.Errorf("gRPC message recv limit (%d bytes) must be greater than send limit (%d bytes)", cfg.MaxCallRecvMsgSize, cfg.MaxCallSendMsgSize)
   469→		}
   470→		callOpts := []grpc.CallOption{
   471→			defaultWaitForReady,
   472→			defaultMaxCallSendMsgSize,
   473→			defaultMaxCallRecvMsgSize,
   474→		}
   475→		if cfg.MaxCallSendMsgSize > 0 {
   476→			callOpts[1] = grpc.MaxCallSendMsgSize(cfg.MaxCallSendMsgSize)
   477→		}
   478→		if cfg.MaxCallRecvMsgSize > 0 {
   479→			callOpts[2] = grpc.MaxCallRecvMsgSize(cfg.MaxCallRecvMsgSize)
   480→		}
   481→		client.callOpts = callOpts
   482→	}
   483→
   484→	client.resolver = resolver.New(cfg.Endpoints...)
   485→
   486→	if len(cfg.Endpoints) < 1 {
   487→		client.cancel()
   488→		return nil, errors.New("at least one Endpoint is required in client config")
   489→	}
   490→	client.SetEndpoints(cfg.Endpoints...)
   491→
   492→	// Use a provided endpoint target so that for https:// without any tls config given, then
   493→	// grpc will assume the certificate server name is the endpoint host.
   494→	conn, err := client.dialWithBalancer()
   495→	if err != nil {
   496→		client.cancel()
   497→		client.resolver.Close()
   498→		// TODO: Error like `fmt.Errorf(dialing [%s] failed: %v, strings.Join(cfg.Endpoints, ";"), err)` would help with debugging a lot.
   499→		return nil, err
   500→	}
   501→	client.conn = conn
   502→
   503→	client.Cluster = NewCluster(client)
   504→	client.KV = NewKV(client)
   505→	client.Lease = NewLease(client)
   506→	client.Watcher = NewWatcher(client)
   507→	client.Auth = NewAuth(client)
   508→	client.Maintenance = NewMaintenance(client)
   509→
   510→	// get token with established connection
   511→	ctx, cancel = client.ctx, func() {}
   512→	if client.cfg.DialTimeout > 0 {
   513→		ctx, cancel = context.WithTimeout(ctx, client.cfg.DialTimeout)
   514→	}
   515→	err = client.getToken(ctx)
   516→	if err != nil {
   517→		client.Close()
   518→		cancel()
   519→		// TODO: Consider fmt.Errorf("communicating with [%s] failed: %v", strings.Join(cfg.Endpoints, ";"), err)
   520→		return nil, err
   521→	}
   522→	cancel()
   523→
   524→	if cfg.RejectOldCluster {
   525→		if err := client.checkVersion(); err != nil {
   526→			client.Close()
   527→			return nil, err
   528→		}
   529→	}
   530→
   531→	go client.autoSync()
   532→	return client, nil
   533→}
