   614→// isHaltErr returns true if the given error and context indicate no forward
   615→// progress can be made, even after reconnecting.
   616→func isHaltErr(ctx context.Context, err error) bool {
   617→	if ctx != nil && ctx.Err() != nil {
   618→		return true
   619→	}
   620→	if err == nil {
   621→		return false
   622→	}
   623→	ev, _ := status.FromError(err)
   624→	// Unavailable codes mean the system will be right back.
   625→	// (e.g., can't connect, lost leader)
   626→	// Treat Internal codes as if something failed, leaving the
   627→	// system in an inconsistent state, but retrying could make progress.
   628→	// (e.g., failed in middle of send, corrupted frame)
   629→	// TODO: are permanent Internal errors possible from grpc?
   630→	return ev.Code() != codes.Unavailable && ev.Code() != codes.Internal
   631→}
   632→
   633→// isUnavailableErr returns true if the given error is an unavailable error
   634→func isUnavailableErr(ctx context.Context, err error) bool {
   635→	if ctx != nil && ctx.Err() != nil {
   636→		return false
   637→	}
   638→	if err == nil {
   639→		return false
   640→	}
   641→	ev, ok := status.FromError(err)
   642→	if ok {
   643→		// Unavailable codes mean the system will be right back.
   644→		// (e.g., can't connect, lost leader)
   645→		return ev.Code() == codes.Unavailable
   646→	}
   647→	return false
   648→}
