   650→// ContextError converts the error into an EtcdError if the error message matches one of
   651→// the defined messages; otherwise, it tries to retrieve the context error.
   652→func ContextError(ctx context.Context, err error) error {
   653→	if err == nil {
   654→		return nil
   655→	}
   656→	err = rpctypes.Error(err)
   657→	var serverErr rpctypes.EtcdError
   658→	if errors.As(err, &serverErr) {
   659→		return err
   660→	}
   661→	if ev, ok := status.FromError(err); ok {
   662→		code := ev.Code()
   663→		switch code {
   664→		case codes.DeadlineExceeded:
   665→			fallthrough
   666→		case codes.Canceled:
   667→			if ctx.Err() != nil {
   668→				err = ctx.Err()
   669→			}
   670→		}
   671→	}
   672→	return err
   673→}
