   675→func canceledByCaller(stopCtx context.Context, err error) bool {
   676→	if stopCtx.Err() == nil || err == nil {
   677→		return false
   678→	}
   679→
   680→	return errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded)
   681→}
