   683→// IsConnCanceled returns true, if error is from a closed gRPC connection.
   684→// ref. https://github.com/grpc/grpc-go/pull/1854
   685→func IsConnCanceled(err error) bool {
   686→	if err == nil {
   687→		return false
   688→	}
   689→
   690→	// >= gRPC v1.23.x
   691→	s, ok := status.FromError(err)
   692→	if ok {
   693→		// connection is canceled or server has already closed the connection
   694→		return s.Code() == codes.Canceled || s.Message() == "transport is closing"
   695→	}
   696→
   697→	// >= gRPC v1.10.x
   698→	if errors.Is(err, context.Canceled) {
   699→		return true
   700→	}
   701→
   702→	// <= gRPC v1.7.x returns 'errors.New("grpc: the client connection is closing")'
   703→	return strings.Contains(err.Error(), "grpc: the client connection is closing")
   704→}
