    86→}
    87→
    88→func (resp *DeleteResponse) OpResponse() OpResponse {
    89→	return OpResponse{del: resp}
    90→}
    91→
    92→func (resp *TxnResponse) OpResponse() OpResponse {
    93→	return OpResponse{txn: resp}
    94→}
