    56→func (m *endpointManager) Update(ctx context.Context, updates []*UpdateWithOpts) (err error) {
    57→	ops := make([]clientv3.Op, 0, len(updates))
    58→	for _, update := range updates {
    59→		if !strings.HasPrefix(update.Key, m.target+"/") {
    60→			return status.Errorf(codes.InvalidArgument, "endpoints: endpoint key should be prefixed with '%s/' got: '%s'", m.target, update.Key)
    61→		}
    62→
    63→		switch update.Op {
    64→		case Add:
    65→			internalUpdate := &internal.Update{
    66→				Op:       internal.Add,
    67→				Addr:     update.Endpoint.Addr,
    68→				Metadata: update.Endpoint.Metadata,
    69→			}
    70→
    71→			var v []byte
    72→			if v, err = json.Marshal(internalUpdate); err != nil {
    73→				return status.Error(codes.InvalidArgument, err.Error())
    74→			}
    75→			ops = append(ops, clientv3.OpPut(update.Key, string(v), update.Opts...))
    76→		case Delete:
    77→			ops = append(ops, clientv3.OpDelete(update.Key, update.Opts...))
    78→		default:
    79→			return status.Error(codes.InvalidArgument, "endpoints: bad update op")
    80→		}
    81→	}
    82→	_, err = m.client.KV.Txn(ctx).Then(ops...).Commit()
    83→	return err
    84→}
