    97→	if err != nil {
    98→		return nil, err
    99→	}
   100→
   101→	lg := m.client.GetLogger()
   102→	initUpdates := make([]*Update, 0, len(resp.Kvs))
   103→	for _, kv := range resp.Kvs {
   104→		var iup internal.Update
   105→		if err := json.Unmarshal(kv.Value, &iup); err != nil {
