   125→func (m *endpointManager) watch(ctx context.Context, rev int64, upch chan []*Update) {
   126→	defer close(upch)
   127→
   128→	lg := m.client.GetLogger()
   129→	opts := []clientv3.OpOption{clientv3.WithRev(rev), clientv3.WithPrefix()}
   130→	key := m.target + "/"
   131→	wch := m.client.Watch(ctx, key, opts...)
   132→	for {
   133→		select {
   134→		case <-ctx.Done():
   135→			return
   136→		case wresp, ok := <-wch:
   137→			if !ok {
   138→				lg.Warn("watch closed", zap.String("target", m.target))
   139→				return
   140→			}
   141→			if wresp.Err() != nil {
   142→				lg.Warn("watch failed", zap.String("target", m.target), zap.Error(wresp.Err()))
   143→				return
   144→			}
   145→
   146→			deltaUps := make([]*Update, 0, len(wresp.Events))
   147→			for _, e := range wresp.Events {
   148→				var iup internal.Update
   149→				var err error
   150→				var op Operation
   151→				switch e.Type {
   152→				case clientv3.EventTypePut:
   153→					err = json.Unmarshal(e.Kv.Value, &iup)
   154→					op = Add
   155→					if err != nil {
   156→						lg.Warn("unmarshal endpoint update failed", zap.String("key", string(e.Kv.Key)), zap.Error(err))
   157→						continue
   158→					}
   159→				case clientv3.EventTypeDelete:
   160→					iup = internal.Update{Op: internal.Delete}
   161→					op = Delete
   162→				default:
   163→					continue
   164→				}
   165→				up := &Update{Op: op, Key: string(e.Kv.Key), Endpoint: Endpoint{Addr: iup.Addr, Metadata: iup.Metadata}}
   166→				deltaUps = append(deltaUps, up)
   167→			}
   168→			if len(deltaUps) > 0 {
   169→				upch <- deltaUps
   170→			}
   171→		}
   172→	}
   173→}
